const month = new Date().getMonth() + 1;
let season, services;

if (month >= 3 && month <= 5) {
  season = 'spring';
  services = ['spring cleanup', 'lawn aeration', 'overseeding', 'fertilizer application', 'mulching', 'garden bed prep'];
} else if (month >= 6 && month <= 8) {
  season = 'summer';
  services = ['lawn mowing', 'weed control', 'irrigation management', 'hedge trimming', 'grub prevention', 'drought care'];
} else if (month >= 9 && month <= 11) {
  season = 'fall';
  services = ['leaf removal', 'fall cleanup', 'lawn aeration', 'overseeding', 'gutter cleaning', 'winterization prep'];
} else {
  season = 'winter';
  services = ['snow removal', 'ice management', 'salt application', 'driveway clearing', 'sidewalk maintenance', 'emergency snow service'];
}

const quarter = `Q${Math.ceil(month / 3)} ${new Date().getFullYear()}`;

return [{ json: { season, services, quarter, month } }];

const response = $input.first().json;
const season = $('Determine Season').first().json.season;
const quarter = $('Determine Season').first().json.quarter;

// Extract text content from Anthropic response
const textBlock = response.content?.find(b => b.type === 'text');
if (!textBlock) throw new Error('No text in AI response');

let faqs;
try {
  // Try to parse JSON from the response
  const jsonMatch = textBlock.text.match(/\[\s*\{[\s\S]*\}\s*\]/);
  faqs = JSON.parse(jsonMatch ? jsonMatch[0] : textBlock.text);
} catch (e) {
  throw new Error('Failed to parse FAQ JSON: ' + e.message);
}

// Format for Telegram
const seasonEmoji = { spring: '\ud83c\udf31', summer: '\u2600\ufe0f', fall: '\ud83c\udf42', winter: '\u2744\ufe0f' };
let telegramText = `${seasonEmoji[season] || ''} *GBP FAQ Rotation — ${season.charAt(0).toUpperCase() + season.slice(1)} ${quarter}*\n\n`;
telegramText += `${faqs.length} FAQs generated for review:\n\n`;

faqs.forEach((faq, i) => {
  telegramText += `*Q${i + 1}:* ${faq.question}\n`;
  telegramText += `*A:* ${faq.answer}\n\n`;
});

telegramText += `\n_Add these to your GBP Q&A section. Go to Google Maps > Your Business > Q&A > Ask a question (ask & answer yourself)._`;

return [{ json: { faqs, faq_count: faqs.length, season, quarter, telegram_text: telegramText } }];
